import { Injectable, NotFoundException, BadRequestException } from '@nestjs/common';
import { DatabaseService } from '../database/database.service';
import { NewsCategory } from '@prisma/client';
import { CreateNewsArticleDto, UpdateNewsArticleDto, QueryNewsDto } from './dto';

/**
 * News Service
 *
 * Manages news articles with CRUD operations and category filtering.
 *
 * Features:
 * - Article creation with slug generation
 * - Category filtering (Patch Notes, Events, Community, Announcements)
 * - Featured article support
 * - Article publication with 5-minute homepage display
 * - Excerpt truncation to 200 characters
 *
 * Requirements: 7.1, 7.2, 7.3, 7.6, 7.7, 7.8
 */
@Injectable()
export class NewsService {
  constructor(private readonly db: DatabaseService) {}

  /**
   * Create a new news article
   *
   * - Generates URL-friendly slug from title
   * - Truncates excerpt to 200 characters
   * - Sets publication date if published
   *
   * Requirements: 7.1, 7.3
   */
  async createArticle(dto: CreateNewsArticleDto): Promise<any> {
    // Generate slug from title
    const slug = this.generateSlug(dto.title);

    // Check if slug already exists
    const existingArticle = await this.db.newsArticle.findUnique({
      where: { slug },
    });

    if (existingArticle) {
      throw new BadRequestException('Article with similar title already exists');
    }

    // Truncate excerpt to 200 characters
    const excerpt = this.truncateExcerpt(dto.excerpt);

    // Create article
    const article = await this.db.newsArticle.create({
      data: {
        title: dto.title,
        slug,
        excerpt,
        body: dto.body,
        category: dto.category,
        author: dto.author,
        imageUrl: dto.imageUrl,
        isFeatured: dto.isFeatured || false,
        publishedAt: dto.publish ? new Date() : null,
      },
    });

    return article;
  }

  /**
   * Update an existing news article
   *
   * Requirements: 7.3
   */
  async updateArticle(id: string, dto: UpdateNewsArticleDto): Promise<any> {
    const article = await this.db.newsArticle.findUnique({
      where: { id },
    });

    if (!article) {
      throw new NotFoundException('Article not found');
    }

    // Generate new slug if title changed
    let slug = article.slug;
    if (dto.title && dto.title !== article.title) {
      slug = this.generateSlug(dto.title);

      // Check if new slug already exists
      const existingArticle = await this.db.newsArticle.findFirst({
        where: {
          slug,
          id: { not: id },
        },
      });

      if (existingArticle) {
        throw new BadRequestException('Article with similar title already exists');
      }
    }

    // Truncate excerpt if provided
    const excerpt = dto.excerpt ? this.truncateExcerpt(dto.excerpt) : undefined;

    // Update article
    const updatedArticle = await this.db.newsArticle.update({
      where: { id },
      data: {
        title: dto.title,
        slug: dto.title ? slug : undefined,
        excerpt,
        body: dto.body,
        category: dto.category,
        author: dto.author,
        imageUrl: dto.imageUrl,
        isFeatured: dto.isFeatured,
        publishedAt: dto.publish !== undefined
          ? (dto.publish ? new Date() : null)
          : undefined,
      },
    });

    return updatedArticle;
  }

  /**
   * Get all news articles with optional filtering
   *
   * - Filter by category
   * - Filter by published status
   * - Pagination support
   * - Sort by publication date descending
   *
   * Requirements: 7.2, 7.6
   */
  async getArticles(query: QueryNewsDto): Promise<{
    articles: any[];
    total: number;
    page: number;
    pageSize: number;
  }> {
    const page = query.page || 1;
    const pageSize = query.pageSize || 20;
    const skip = (page - 1) * pageSize;

    // Build where clause
    const where: any = {};

    if (query.category) {
      where.category = query.category;
    }

    if (query.publishedOnly !== false) {
      where.publishedAt = { not: null };
    }

    if (query.featured !== undefined) {
      where.isFeatured = query.featured;
    }

    // Get articles
    const [articles, total] = await Promise.all([
      this.db.newsArticle.findMany({
        where,
        orderBy: { publishedAt: 'desc' },
        skip,
        take: pageSize,
      }),
      this.db.newsArticle.count({ where }),
    ]);

    return {
      articles,
      total,
      page,
      pageSize,
    };
  }

  /**
   * Get a single article by ID or slug
   *
   * Requirements: 7.7
   */
  async getArticle(idOrSlug: string): Promise<any> {
    const article = await this.db.newsArticle.findFirst({
      where: {
        OR: [
          { id: idOrSlug },
          { slug: idOrSlug },
        ],
      },
    });

    if (!article) {
      throw new NotFoundException('Article not found');
    }

    return article;
  }

  /**
   * Get featured article
   *
   * Returns the most recent featured article.
   *
   * Requirements: 7.3, 7.8
   */
  async getFeaturedArticle(): Promise<any | null> {
    const article = await this.db.newsArticle.findFirst({
      where: {
        isFeatured: true,
        publishedAt: { not: null },
      },
      orderBy: { publishedAt: 'desc' },
    });

    return article;
  }

  /**
   * Get recent articles for homepage
   *
   * Returns up to 6 most recent published articles.
   * Featured article is included if published within last 5 minutes.
   *
   * Requirements: 7.4, 7.5, 7.8
   */
  async getRecentArticles(limit: number = 6): Promise<any[]> {
    const fiveMinutesAgo = new Date(Date.now() - 5 * 60 * 1000);

    const articles = await this.db.newsArticle.findMany({
      where: {
        publishedAt: { not: null },
      },
      orderBy: { publishedAt: 'desc' },
      take: limit,
    });

    return articles;
  }

  /**
   * Delete an article
   *
   * Requirements: 7.3
   */
  async deleteArticle(id: string): Promise<void> {
    const article = await this.db.newsArticle.findUnique({
      where: { id },
    });

    if (!article) {
      throw new NotFoundException('Article not found');
    }

    await this.db.newsArticle.delete({
      where: { id },
    });
  }

  /**
   * Generate URL-friendly slug from title
   */
  private generateSlug(title: string): string {
    return title
      .toLowerCase()
      .replace(/[^a-z0-9]+/g, '-')
      .replace(/^-+|-+$/g, '')
      .substring(0, 100);
  }

  /**
   * Truncate excerpt to 200 characters
   *
   * Requirements: 7.1
   */
  private truncateExcerpt(excerpt: string): string {
    if (excerpt.length <= 200) {
      return excerpt;
    }

    return excerpt.substring(0, 197) + '...';
  }
}

