import {
  Controller,
  Get,
  Post,
  Put,
  Delete,
  Body,
  Param,
  Query,
  UseGuards,
  HttpCode,
  HttpStatus,
} from '@nestjs/common';
import { AuthGuard } from '@nestjs/passport';
import { NewsService } from './news.service';
import { CreateNewsArticleDto, UpdateNewsArticleDto, QueryNewsDto } from './dto';

/**
 * News Controller
 *
 * Handles all news article endpoints:
 * - Article CRUD operations
 * - Category filtering
 * - Featured article retrieval
 * - Recent articles for homepage
 *
 * Requirements: 7.1, 7.2, 7.3, 7.6, 7.7, 7.8
 */
@Controller('news')
export class NewsController {
  constructor(private readonly newsService: NewsService) {}

  /**
   * POST /news
   *
   * Create a new news article.
   * Requires authentication (admin/moderator).
   *
   * Requirements: 7.1, 7.3
   */
  @Post()
  @UseGuards(AuthGuard('jwt'))
  @HttpCode(HttpStatus.CREATED)
  async createArticle(@Body() dto: CreateNewsArticleDto) {
    const article = await this.newsService.createArticle(dto);
    return {
      message: 'Article created successfully',
      article,
    };
  }

  /**
   * GET /news
   *
   * Get all news articles with optional filtering.
   * Supports category filter, pagination, and published status.
   *
   * Requirements: 7.2, 7.6
   */
  @Get()
  async getArticles(@Query() query: QueryNewsDto) {
    return this.newsService.getArticles(query);
  }

  /**
   * GET /news/featured
   *
   * Get the featured article.
   *
   * Requirements: 7.3, 7.8
   */
  @Get('featured')
  async getFeaturedArticle() {
    const article = await this.newsService.getFeaturedArticle();
    return { article };
  }

  /**
   * GET /news/recent
   *
   * Get recent articles for homepage (max 6).
   *
   * Requirements: 7.4, 7.5, 7.8
   */
  @Get('recent')
  async getRecentArticles(@Query('limit') limit?: string) {
    const articles = await this.newsService.getRecentArticles(
      limit ? parseInt(limit, 10) : 6,
    );
    return { articles };
  }

  /**
   * GET /news/:idOrSlug
   *
   * Get a single article by ID or slug.
   *
   * Requirements: 7.7
   */
  @Get(':idOrSlug')
  async getArticle(@Param('idOrSlug') idOrSlug: string) {
    const article = await this.newsService.getArticle(idOrSlug);
    return { article };
  }

  /**
   * PUT /news/:id
   *
   * Update an existing article.
   * Requires authentication (admin/moderator).
   *
   * Requirements: 7.3
   */
  @Put(':id')
  @UseGuards(AuthGuard('jwt'))
  async updateArticle(
    @Param('id') id: string,
    @Body() dto: UpdateNewsArticleDto,
  ) {
    const article = await this.newsService.updateArticle(id, dto);
    return {
      message: 'Article updated successfully',
      article,
    };
  }

  /**
   * DELETE /news/:id
   *
   * Delete an article.
   * Requires authentication (admin/moderator).
   *
   * Requirements: 7.3
   */
  @Delete(':id')
  @UseGuards(AuthGuard('jwt'))
  @HttpCode(HttpStatus.NO_CONTENT)
  async deleteArticle(@Param('id') id: string) {
    await this.newsService.deleteArticle(id);
  }
}

import { Module } from '@nestjs/common';
